    ["Rename..."] = "重新命名...",
    ["Render a fake spell on the castbar for visual tuning."] = "在施法條上渲染假法術以供視覺調整。",
    ["Render bars horizontally (width fills left to right) or vertically (height fills upward). Vertical mode enables the controls below."] = "將條水平（寬度向右填滿）或垂直（高度向上填滿）渲染。垂直模式會啟用下方控制項。",
    ["Render forces progress as a filling bar or as text only."] = "將進度渲染為填充條或僅文字。",
    ["Render layer for boss unit frames shown during encounters."] = "首領單位框架在遭遇戰中顯示的渲染層級。",
    ["Render layer for custom item and spell tracker bars you've configured in the Cooldown Manager."] = "你在 Cooldown Manager 中設定的自訂物品與法術追蹤條之渲染層級。",
    ["Render layer for player status icons such as leader, PvP, combat, and resting indicators."] = "玩家狀態圖示（如隊長、PvP、戰鬥與休息指示器）的渲染層級。",
    ["Render layer for the Buff Bar viewer. Raise this if buff bars are being hidden by other HUD pieces."] = "Buff Bar 檢視器的渲染層級。若 Buff 條被其他 HUD 元件遮住，請提高此值。",
    ["Render layer for the Buff Icon viewer. Raise this if buff icons are being hidden by other HUD pieces."] = "Buff Icon 檢視器的渲染層級。若 Buff 圖示被其他 HUD 元件遮住，請提高此值。",
    ["Render layer for the Essential cooldowns viewer. Higher values draw over lower-layered HUD elements."] = "重要冷卻檢視器的渲染層級。較高數值會繪製在較低層級 HUD 元件之上。",
    ["Render layer for the Utility cooldowns viewer. Higher values draw over lower-layered HUD elements."] = "工具冷卻檢視器的渲染層級。較高數值會繪製在較低層級 HUD 元件之上。",
    ["Render layer for the focus unit frame."] = "焦點單位框架的渲染層級。",
    ["Render layer for the pet unit frame."] = "寵物單位框架的渲染層級。",
    ["Render layer for the player castbar. Raise this if your castbar is being hidden behind other HUD elements."] = "玩家施法條的渲染層級。若施法條被其他 HUD 元件遮住，請提高此值。",
    ["Render layer for the player unit frame. Higher values draw over lower-layered HUD elements."] = "玩家單位框架的渲染層級。較高數值會繪製在較低層級 HUD 元件之上。",
    ["Render layer for the primary resource bar (mana, rage, energy, etc.). Higher values draw over lower-layered HUD elements."] = "主要資源條（法力、怒氣、能量等）的渲染層級。較高數值會繪製在較低層級 HUD 元件之上。",
    ["Render layer for the secondary resource bar (combo points, holy power, soul shards, etc.)."] = "次要資源條（連擊點、神聖能量、靈魂碎片等）的渲染層級。",
    ["Render layer for the skyriding vigor and dynamic flight HUD shown while mounted."] = "騎乘時顯示的空騎活力與動態飛行 HUD 的渲染層級。",
    ["Render layer for the target castbar. Raise this to keep enemy casts visible above other HUD elements."] = "目標施法條的渲染層級。請提高此值以保持敵方施法可見於其他 HUD 元件之上。",
    ["Render layer for the target of target frame."] = "目標的目標框架的渲染層級。",
    ["Render layer for the target unit frame. Higher values draw over lower-layered HUD elements."] = "目標單位框架的渲染層級。較高數值會繪製在較低層級 HUD 元件之上。",
    ["Render the duration and spell-name text on vertical bars. Turn off for icon-only vertical bars."] = "在垂直條上渲染持續時間與法術名稱文字。關閉則只顯示圖示式垂直條。",
    ["Render the zone label in all uppercase letters."] = "將區域標籤以全大寫字母渲染。",
