    ["Thickness"] = "粗細",
    ["Thickness of each Pixel Glow line."] = "每條 Pixel Glow 線條的粗細。",
    ["Thickness of each glow line. Only used by Pixel Glow."] = "每條發光線的粗細。僅供 Pixel Glow 使用。",
    ["Thickness of the bar's border in pixels. 0 removes the border entirely."] = "條邊框的像素粗細。設為 0 可完全移除邊框。",
    ["Thickness of the bar's screen-inner edge border. Set to 0 to hide it."] = "條內側邊緣邊框的粗細。設為 0 可隱藏。",
    ["Thickness of the border drawn around buff and debuff icons."] = "增益與減益圖示邊框的粗細。",
    ["Thickness of the border drawn around the icon. Set to 0 to hide the border."] = "圖示周圍邊框的粗細。設為 0 可隱藏邊框。",
    ["Thickness of the border drawn around the minimap."] = "小地圖周圍邊框的粗細。",
