    ["Thickness of the border drawn around the spell icon, in pixels."] = "法術圖示周圍邊框的粗細（像素）。",
    ["Thickness of the castbar outline in pixels. 0 hides the outline."] = "施法條外框的粗細（像素）。設為 0 可隱藏外框。",
    ["Thickness of the crosshair lines in pixels."] = "準星線條粗細（像素）。",
    ["Thickness of the drawer border. Set to 0 to hide the border."] = "抽屜邊框粗細。設為 0 可隱藏邊框。",
    ["Thickness of the icon border in pixels."] = "圖示邊框粗細（像素）。",
